import * as React from 'react';
import { defaultIsEqual, useLatestState } from '@universe-design/react-utilities';
import type { EqualFunc } from '@universe-design/react-utilities';
import { useIsomorphicLayoutEffect as useLayoutEffect } from './useIsomorphicLayoutEffect';

/**
 * 半受控模式
 * @internal
 */
export function useSyncState<T>(
  propState: T,
  {
    isEqual = defaultIsEqual,
  }: {
    isEqual?: EqualFunc<T>;
  } = {},
) {
  const isUpdate = React.useRef<boolean>(false);
  const [internalState, setInternalState, stateRef] = useLatestState(propState);
  const [distinctPropState, setDistinctPropState] = React.useState<T>(propState);

  if (!isEqual(distinctPropState, propState)) {
    setDistinctPropState(propState);
  }

  useLayoutEffect(() => {
    if (!isUpdate.current) {
      isUpdate.current = true;
      return;
    }
    if (!isEqual(stateRef.current, distinctPropState)) {
      setInternalState(distinctPropState);
    }
  }, [isEqual, setInternalState, distinctPropState, stateRef]);

  return [internalState, setInternalState, stateRef] as const;
}

export default useSyncState;
